INSERT INTO `users` VALUES (1,'Optik Kasih','optikasih@gmail.com',NULL,NULL,NULL,NULL,NULL,'2026-06-17 04:12:07','$2y$12$wPPP.TXKGmA5WA1uO.Gfh.wsQgR5kps4beJt5Nyq/x9QMbdyqXWfK','super_admin',NULL,'2026-06-17 04:12:07','2026-06-17 04:12:07'),(2,'Optik Kasih Kayu Manis 27C','OptikayuM@gmail.com','08953308124','10.30-21.00 WIB','Jl. Kayu Manis No.27 C, Tampan, Payung Sekaki, Kota Pekanbaru, Riau 28291','Cabang Optik Kasih di Jalan Kayu Manis No. 27 C, Pekanbaru merupakan usaha optik yang telah beroperasi sejak tahun 2007 dan bergerak dalam penjualan alat bantu penglihatan seperti kacamata serta lensa kontak. Cabang ini melayani pemeriksaan mata, pemilihan frame kacamata, dan penjualan produk optik untuk berbagai kebutuhan pelanggan. Dengan pengalaman yang telah dimiliki selama bertahun-tahun, Optik Kasih berkomitmen memberikan pelayanan yang ramah dan membantu pelanggan mendapatkan solusi penglihatan yang sesuai dengan kebutuhan mereka.','<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3989.642498007693!2d101.42102159999999!3d0.5378976999999999!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x31d5ab9217f79e4f%3A0xc9b7a6a9dd86cfd7!2sOptik%20Kasih!5e0!3m2!1sid!2sid!4v1782274991386!5m2!1sid!2sid\" width=\"600\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"strict-origin-when-cross-origin\"></iframe>',NULL,'$2y$12$08p/HHzmxkoIXWRyKKOkAu8BM7ImUlGDNSGkkaHpE5euhSHYdL/TC','admin',NULL,'2026-06-23 21:28:23','2026-06-23 21:28:23');
